import React, { useMemo, useState } from "react";
import { Link, NavLink, useNavigate } from "react-router-dom";
import "./Header.css";
import useAuth from "../../hooks/useAuth";

const Header = () => {
  const navigate = useNavigate();
  const [menuOpen, setMenuOpen] = useState(false);

  const auth = useAuth?.() || {};
  const isAuthenticated = auth.isAuthenticated ?? !!localStorage.getItem("accessToken");
  const user = auth.user ?? null;

  const role = useMemo(() => {
    if (user?.role) return user.role;
    const token = localStorage.getItem("accessToken");
    if (!token) return null;
    try {
      const payload = JSON.parse(atob(token.split(".")[1]));
      return payload.role || null;
    } catch {
      return null;
    }
  }, [user]);

  const isAdmin = role === "ADMIN" || role === "SUPERADMIN";

  const guestMenus = [
    { label: "소개", to: "/#intro" },
    { label: "가격", to: "/#pricing" },
    { label: "도움말", to: "/#help" },
    { label: "무료 체험", to: "/trial", highlight: true },
    { label: "다운로드", to: "/download" },
  ];

  const memberMenus = [
    { label: "소개", to: "/#intro" },
    { label: "가격", to: "/#pricing" },
    { label: "도움말", to: "/#help" },
    { label: "다운로드", to: "/download" },
    { label: "대시보드", to: "/dashboard" },
    { label: "마이페이지", to: "/mypage" },
    ...(isAdmin ? [{ label: "관리자페이지", to: "/admin" }] : []),
  ];

  const menus = isAuthenticated ? memberMenus : guestMenus;

  const handleLogout = () => {
    if (auth.logout) auth.logout();
    else {
      localStorage.removeItem("accessToken");
      localStorage.removeItem("refreshToken");
    }
    navigate("/");
  };

  return (
    <header className="matey-header">
      <div className="matey-header__inner">
        <Link to="/" className="matey-logo">
          <div className="matey-logo__mark">M</div>
          <div className="matey-logo__text">
            <strong>메이티</strong>
            <span>먼저 다가오는 AI 메이트</span>
          </div>
        </Link>

        <nav className={`matey-nav ${menuOpen ? "open" : ""}`}>
          {menus.map((menu) => (
            <a key={menu.label} href={menu.to} className={menu.highlight ? "nav-chip" : ""}>
              {menu.label}
            </a>
          ))}
        </nav>

        <div className="matey-header__actions">
          {!isAuthenticated ? (
            <>
              <NavLink to="/login" className="btn-text">로그인</NavLink>
              <NavLink to="/signup" className="btn-primary">회원가입</NavLink>
            </>
          ) : (
            <>
              <span className="user-pill">
                {isAdmin ? "관리자" : "메이트 사용자"}
              </span>
              <button onClick={handleLogout} className="btn-secondary">
                로그아웃
              </button>
            </>
          )}

          <button
            className="mobile-menu-btn"
            onClick={() => setMenuOpen((prev) => !prev)}
            aria-label="메뉴 열기"
          >
            <span />
            <span />
            <span />
          </button>
        </div>
      </div>
    </header>
  );
};

export default Header;
